<template>
  <nav class="side-menu__container">
    <input type="text" placeholder="Search" class="input__text">
    <ul class="side-menu__filter-list">
      <li class="side-menu__filter-dropdown" v-for="(term, indexG, key) in dataProps" :key="key">
        <span class="side-menu__filter-term" @click="toggleDropdown">{{term.name}}</span>
        <div class="side-menu__form-wrapper">
          <form class="side-menu__filter-form" action="submit" name="division">
            <div class="side-menu__form-item" v-for="(values, index, key) in term.values" :key="key">
              <input type="radio" :value="values" :name="term.name" :id="values" v-model="activeHeaders[indexG]">
              <label class="side-menu__form-label" :for="term.name">{{values}}</label>
            </div>
          </form>
        </div>
      </li>
    </ul>
  </nav>
</template>

<script>
import dataAdvanced from '../assets/dataAdvanced.json'
export default {
  name: 'SideMenu',
  props: {
    dataProps: {
      type: Object,
      required: true
    }
  },
  data () {
    return {
      dataAdvanced: dataAdvanced,
      valuesArray: [],
      activeHeaders: [
        'Current Customer',
        '2020',
        'Q2',
        'OLA'
      ]
    }
  },
  methods: {
    toggleDropdown (e) {
      e.target.parentNode.classList.toggle('dropdown--opened')
    }
  },
  computed: {
    addValueToArray () {
      const filter = this.dataAdvanced.filter(i => Object.values(i).forEach(element => this.activeHeaders.includes(element)))
      return filter
    }
  }
}
</script>
